const pr       = $('GitHub PR Trigger').item.json.pull_request;
const repo     = $('GitHub PR Trigger').item.json.repository;
const rawDiff  = $input.item.json.data || $input.item.json.body || '';

const prTitle  = pr.title || 'Untitled PR';
const prNumber = pr.number;
const prUrl    = pr.html_url;
const prBody   = pr.body || '';
const author   = pr.user?.login || 'unknown';
const branch   = pr.head?.ref || 'unknown';
const base     = pr.base?.ref || 'main';
const repoName = repo.full_name || 'johanneslungelo021-cmd/Apex';

// Detect platform from PR labels or title keywords
const labels    = ($('GitHub PR Trigger').item.json.pull_request.labels || []).map(l => l.name.toLowerCase());
const isNumerai = labels.includes('numerai') || prTitle.toLowerCase().includes('numerai') || prBody.toLowerCase().includes('numerai');
const platform  = isNumerai ? 'Numerai' : 'Moltcorp';

const ctx = `PR #${prNumber}: "${prTitle}" | Author: ${author} | Branch: ${branch} → ${base} | Repo: ${repoName} | URL: ${prUrl}`;

let deepseekPrompt, qwenPrompt, kimiPrompt;

if (platform === 'Numerai') {
  deepseekPrompt = [
    'You are a Quantitative Auditor for Numerai (https://numer.ai/).',
    'Analyse this code diff for overfitting risks, MMC impact, and data leakage.',
    'Output: VERDICT: PASS or FAIL | RISK_LEVEL: low/medium/high | FINDINGS: (numbered) | MMC_IMPACT: (estimate)',
    '', ctx, '', 'Diff:', rawDiff.substring(0, 8000)
  ].join('\n');

  qwenPrompt = [
    'You are a Python Feature Engineering Agent for Numerai.',
    'Review this diff for compute efficiency and suggest 3 feature engineering improvements.',
    'Output: CODE_QUALITY_SCORE: X/10 | OPTIMISATIONS: (numbered with code) | EFFICIENCY_GAIN: (estimate)',
    '', ctx, '', 'Diff:', rawDiff.substring(0, 8000)
  ].join('\n');

  kimiPrompt = [
    '<think>',
    'You are a Numerai Meta-Analyst. Evaluate this strategy change for tournament viability.',
    'Cross-reference against known Numerai v5.0 patterns and NMR staking risk.',
    'Output: UX_IMPACT: low/medium/high | TOURNAMENT_RISK: low/medium/high | RECOMMENDATIONS: (list)',
    '', ctx, '', 'Diff:', rawDiff.substring(0, 8000),
    '</think>'
  ].join('\n');

} else {
  // Moltcorp / Apex PR
  deepseekPrompt = [
    'You are a Security Auditor for the Apex fintech platform (South Africa).',
    'Hard-review this code diff for: auth bypasses, payment gateway friction, injection vectors, RLS violations, logic errors.',
    'Output: VERDICT: PASS or FAIL | SEVERITY: critical/high/medium/low | FINDINGS: (numbered) | PAYMENT_RISK: yes/no',
    '', ctx, '', 'Diff:', rawDiff.substring(0, 8000)
  ].join('\n');

  qwenPrompt = [
    'You are a Senior TypeScript/Next.js Architect reviewing this PR for the Apex fintech platform.',
    'Check for: redundant loops, type safety violations, missing error boundaries, performance regressions.',
    'Output: CODE_QUALITY_SCORE: X/10 | ISSUES: (numbered) | REWRITES: (show improved snippets)',
    '', ctx, '', 'Diff:', rawDiff.substring(0, 8000)
  ].join('\n');

  kimiPrompt = [
    '<think>',
    'You are a UX/Product Designer for the Apex "African Futurism" platform.',
    'Review this PR for end-user impact: does it break the visual language, UTM tracking, payment flow, or accessibility?',
    'Output: UX_IMPACT: low/medium/high | BREAKING_CHANGES: yes/no | RECOMMENDATIONS: (numbered list)',
    '', ctx, '', 'Diff:', rawDiff.substring(0, 8000),
    '</think>'
  ].join('\n');
}

return [{ json: {
  deepseek_prompt: deepseekPrompt,
  qwen_prompt:     qwenPrompt,
  kimi_prompt:     kimiPrompt,
  target_platform: platform,
  task_type:       'PR_Audit',
  pr_number:       prNumber,
  pr_title:        prTitle,
  pr_url:          prUrl,
  repo_name:       repoName,
  author,
  context:         ctx,
}}];

const items = $input.all();
const modelMap = [
  { id: 'deepseek-r1', label: 'DeepSeek-R1 (Reasoning)' },
  { id: 'qwen3',       label: 'Qwen3 (Analysis)'        },
  { id: 'kimi-k2',     label: 'Kimi K2 (Thinking)'      },
];
return items.map((item, i) => {
  const raw = item.json.response || item.json.message?.content || '[no response]';
  const cleaned = raw.replace(/<think>[\s\S]*?<\/think>/gi, '').trim();
  return { json: {
    model_id:    modelMap[i]?.id    || `model_${i}`,
    model_label: modelMap[i]?.label || `Model ${i}`,
    response:    cleaned,
    raw:         raw,
    word_count:  cleaned.split(/\s+/).length,
    timed_out:   cleaned.length < 10,
    duration_ms: Math.round((item.json.total_duration || 0) / 1e6),
  }};
});

const items    = $input.all();
const platform = $('Prepare Prompts').item.json.target_platform || 'Moltcorp';
const prTitle  = $('Prepare Prompts').item.json.pr_title || '';
const prUrl    = $('Prepare Prompts').item.json.pr_url   || '';
const allOut   = items.every(i => i.json.timed_out);

if (allOut) {
  return [{ json: {
    status: 'FALLBACK', hard_fail: false, fallback_used: true,
    platform, pr_title: prTitle, pr_url: prUrl,
    final_review: '⚠️ **Tri-Model Council** — All 3 models timed out. Manual review required.',
    best_model: 'fallback', best_score: 0,
    all_responses: items.map(i => ({ model: i.json.model_id, score: 0, timed_out: true })),
    timestamp: new Date().toISOString(),
  }}];
}

// Weights: DeepSeek×0.4 + Qwen×0.4 + Kimi×0.2
const scored = items.map(item => {
  const { model_id, response, word_count, timed_out, duration_ms } = item.json;
  if (timed_out) return { ...item.json, score: 0, hard_fail: false };
  const text = response.toLowerCase();
  let score = 0, hardFail = false;

  if (model_id === 'deepseek-r1') {
    const isFail = /verdict:\s*fail/i.test(response);
    if (isFail) { hardFail = true; score = 80 * 0.4; }
    else { score = (/verdict:\s*pass/i.test(response) ? 90 : 60) * 0.4; }
    if (text.includes('critical')) score += 5 * 0.4;

  } else if (model_id === 'qwen3') {
    const m = response.match(/CODE_QUALITY_SCORE:\s*(\d+)/i);
    const q = m ? parseInt(m[1]) : Math.min(word_count / 15, 10);
    score = q * 8 * 0.4;
    if (text.includes('optimis')) score += 8 * 0.4;

  } else if (model_id === 'kimi-k2') {
    const impactMap = { low: 30, medium: 60, high: 90 };
    const m = response.match(/UX_IMPACT:\s*(low|medium|high)/i);
    score = (m ? impactMap[m[1].toLowerCase()] : 50) * 0.2;
    if (/BREAKING_CHANGES:\s*no/i.test(response)) score += 10 * 0.2;
  }

  return { ...item.json, score: Math.round(score * 10) / 10, hard_fail: hardFail };
});

const dsResult  = scored.find(s => s.model_id === 'deepseek-r1');
const hardFail  = dsResult?.hard_fail === true;
const best      = scored.reduce((a, b) => b.score > a.score ? b : a);

// Build the GitHub comment
const verdict   = hardFail ? '🚨 REJECTED' : '✅ APPROVED';
const allScores = scored.map(s =>
  `| ${s.model_label} | ${s.response.substring(0, 120).replace(/\n/g,' ')}... | ${s.score} | ${s.duration_ms}ms |`
).join('\n');

const finalReview = [
  `## ${verdict} by Tri-Model Council`,
  `**PR:** [${prTitle}](${prUrl}) | **Platform:** ${platform}`,
  '',
  `### 🏆 Winning Model: ${best.model_label} (score: ${best.score})`,
  '',
  best.response,
  '',
  '### 📊 All Model Scores',
  '| Model | Summary | Score | Duration |',
  '|-------|---------|-------|----------|',
  allScores,
  '',
  '_Reviewed by Apex Tri-Model Council — DeepSeek-R1 + Qwen3 + Kimi K2_',
].join('\n');

return [{ json: {
  status: hardFail ? 'REJECTED' : 'APPROVED',
  hard_fail: hardFail, fallback_used: false,
  platform, pr_title: prTitle, pr_url: prUrl,
  final_review: finalReview,
  best_model: best.model_id, best_label: best.model_label,
  best_response: best.response, best_score: best.score,
  all_responses: scored.map(s => ({ model: s.model_label, score: s.score, duration_ms: s.duration_ms })),
  timestamp: new Date().toISOString(),
}}];
